// src/ai/aiService.js

const OPENAI_API_KEY = "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";

// helper
function delay(ms) {
  return new Promise((res) => setTimeout(res, ms));
}

// ─────────────────────────────
// AI BLOG GENERATOR 🔥
// ─────────────────────────────
export async function generateBlog(title) {
  try {
    const res = await fetch("https://api.openai.com/v1/chat/completions", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${OPENAI_API_KEY}`,
      },
      body: JSON.stringify({
        model: "gpt-4o-mini",
        messages: [
          {
            role: "system",
            content:
              "Write a high-quality blog post (300-500 words) based on the given title.",
          },
          {
            role: "user",
            content: title,
          },
        ],
      }),
    });

    const data = await res.json();
    return data.choices?.[0]?.message?.content || "";
  } catch (err) {
    console.error(err);
    return "Failed to generate content.";
  }
}

// ─────────────────────────────
// AI TAG GENERATOR
// ─────────────────────────────
export async function generateTags(title, content) {
  try {
    const res = await fetch("https://api.openai.com/v1/chat/completions", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${OPENAI_API_KEY}`,
      },
      body: JSON.stringify({
        model: "gpt-4o-mini",
        messages: [
          {
            role: "system",
            content:
              "Generate 5 relevant tags. Return ONLY JSON array like [\"tag1\",\"tag2\"]",
          },
          {
            role: "user",
            content: `Title: ${title}\nContent: ${content}`,
          },
        ],
      }),
    });

    const data = await res.json();
    const text = data?.choices?.[0]?.message?.content;

    return JSON.parse(text);
  } catch (err) {
    console.error("Tag fallback");

    // fallback
    const words = (title + content).toLowerCase().split(/\W+/);
    return [...new Set(words.filter(w => w.length > 4))].slice(0, 5);
  }
}

// ─────────────────────────────
// WRITING ANALYSIS (mock)
// ─────────────────────────────
export async function analyzeWriting(title, content) {
  await delay(600);

  return {
    score: 8,
    tone: "Professional",
    readability: "Medium",
    strengths: ["Good topic", "Clear flow", "Engaging"],
    improvements: ["Add examples", "Improve intro"],
    rewrittenIntro: `This article explores ${title.toLowerCase()} in depth.`,
  };
}
